import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { roleGuard } from './core/guards/role.guard';

/**
 * EasyFile route tree with per-route `data.flow` metadata.
 * Angular children do not inherit `data`, so each node repeats its own flow.
 * Hash routing is configured in app.config.ts.
 */
export const routes: Routes = [
  { path: '', pathMatch: 'full', redirectTo: 'returns' },

  {
    path: 'login',
    loadComponent: () =>
      import('./pages/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { node: 'login', entry: true, edgesTo: ['returns', 'signup'] } },
  },
  {
    path: 'signup',
    loadComponent: () =>
      import('./pages/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { node: 'signup', edgesTo: ['returns', 'login'] } },
  },

  {
    path: '',
    loadComponent: () =>
      import('./shared/layout.component').then((m) => m.LayoutComponent),
    canActivate: [authGuard],
    children: [
      {
        path: 'returns',
        loadComponent: () =>
          import('./pages/returns-list/returns-list.component').then(
            (m) => m.ReturnsListComponent,
          ),
        data: { flow: { node: 'returns', showInNavbar: true, edgesTo: ['wizard-filing-status'] } },
      },
      {
        path: 'returns/:id/wizard',
        loadComponent: () =>
          import('./pages/wizard/wizard-shell.component').then(
            (m) => m.WizardShellComponent,
          ),
        data: { flow: { node: 'wizard' } },
        children: [
          {
            path: '',
            pathMatch: 'full',
            redirectTo: 'filing-status',
          },
          {
            path: 'filing-status',
            loadComponent: () =>
              import('./pages/wizard/filing-status/filing-status.component').then(
                (m) => m.FilingStatusComponent,
              ),
            data: { flow: { node: 'wizard-filing-status', edgesTo: ['wizard-dependents'] } },
          },
          {
            path: 'dependents',
            loadComponent: () =>
              import('./pages/wizard/dependents/dependents.component').then(
                (m) => m.DependentsComponent,
              ),
            data: { flow: { node: 'wizard-dependents', edgesTo: ['wizard-income'] } },
          },
          {
            path: 'income',
            loadComponent: () =>
              import('./pages/wizard/income/income.component').then(
                (m) => m.IncomeComponent,
              ),
            data: { flow: { node: 'wizard-income', edgesTo: ['wizard-deductions'] } },
          },
          {
            path: 'deductions',
            loadComponent: () =>
              import('./pages/wizard/deductions/deductions.component').then(
                (m) => m.DeductionsComponent,
              ),
            data: { flow: { node: 'wizard-deductions', edgesTo: ['wizard-review'] } },
          },
          {
            path: 'review',
            loadComponent: () =>
              import('./pages/wizard/review/review.component').then(
                (m) => m.ReviewComponent,
              ),
            data: { flow: { node: 'wizard-review', edgesTo: ['returns'] } },
          },
        ],
      },
      {
        path: 'admin/stats',
        canActivate: [roleGuard],
        loadComponent: () =>
          import('./pages/admin-stats/admin-stats.component').then(
            (m) => m.AdminStatsComponent,
          ),
        data: { flow: { node: 'admin-stats', showInNavbar: true, scope: 'admin' } },
      },
      {
        path: 'admin/users',
        canActivate: [roleGuard],
        loadComponent: () =>
          import('./pages/admin-users/admin-users.component').then(
            (m) => m.AdminUsersComponent,
          ),
        data: { flow: { node: 'admin-users', showInNavbar: true, scope: 'admin' } },
      },
      {
        path: 'admin/settings',
        canActivate: [roleGuard],
        loadComponent: () =>
          import('./pages/admin-settings/admin-settings.component').then(
            (m) => m.AdminSettingsComponent,
          ),
        data: { flow: { node: 'admin-settings', showInNavbar: true, scope: 'admin' } },
      },
    ],
  },

  { path: '**', redirectTo: 'returns' },
];
